refsection.programlisting:
rows = 140;
cols = 220;
x = ones(rows, 1) * (1:cols);
y = (1:rows)' * ones(1, cols);

mask = ((x - 60).^2 + (y - 70).^2 <= 35^2) | ..
       ((x - 160).^2 + (y - 70).^2 <= 20^2);
distance = imbwdist(mask, "euclidean");
centers = imbwulterode(mask);
visibleCenters = imdilate(centers, imcreatese("rect", 5, 5));
overlay = imoverlaymask(uint8(mask .* 255), visibleCenters .* 1, [255 0 0], 0.9, %f);

subplot(1, 3, 1);
imshow(uint8(mask .* 255));
xtitle("Two binary objects");
subplot(1, 3, 2);
imshow(immat2gray(distance), hot(64));
xtitle("Distance to background");
subplot(1, 3, 3);
imshow(overlay);
xtitle("Ultimate-erosion centers in red");
